// Entry point: set workflow parameters
const sync_scope = $input.first().json.sync_scope || 'all_active';
const employee_list = $input.first().json.employee_list || [];
const dry_run = $input.first().json.dry_run === true;

return [{
  json: {
    sync_scope,
    employee_list,
    dry_run,
    workflow_start: new Date().toISOString(),
    run_id: `BUPA_SYNC_${Date.now()}`
  }
}];

// Merge, deduplicate, and chunk into batches of 500
const params = $('Set Parameters').first().json;
const activeEmployees = $('Read Active Employees').first().json.result || [];
const vendorEmployees = $('Read Employee Vendors').first().json.result || [];

// Extract PERNRs from both sources
let pernrSet = new Set();

if (params.sync_scope === 'specific_list' && params.employee_list.length > 0) {
  params.employee_list.forEach(p => pernrSet.add(String(p)));
} else {
  // Add active employees
  if (Array.isArray(activeEmployees)) {
    activeEmployees.forEach(emp => {
      if (emp.PERNR) pernrSet.add(String(emp.PERNR));
    });
  }
  // Add vendor employees if scope includes them
  if (params.sync_scope === 'all_active' || params.sync_scope === 'vendors_only') {
    if (Array.isArray(vendorEmployees)) {
      vendorEmployees.forEach(emp => {
        if (emp.PERNR) pernrSet.add(String(emp.PERNR));
      });
    }
  }
}

const allPernrs = Array.from(pernrSet);

// Chunk into batches of 500
const BATCH_SIZE = 500;
const batches = [];
for (let i = 0; i < allPernrs.length; i += BATCH_SIZE) {
  batches.push(allPernrs.slice(i, i + BATCH_SIZE));
}

return [{
  json: {
    total_employees: allPernrs.length,
    batch_count: batches.length,
    batches,
    sync_scope: params.sync_scope,
    dry_run: params.dry_run,
    run_id: params.run_id
  }
}];

// M1 Milestone: Population Selection complete
const data = $('Merge and Chunk').first().json;

return [{
  json: {
    ...data,
    milestone: 'M1',
    milestone_name: 'Population Selection',
    milestone_status: 'COMPLETED',
    milestone_timestamp: new Date().toISOString(),
    message: `M1 complete: ${data.total_employees} employees selected in ${data.batch_count} batches. Dry run mode - no sync executed.`
  }
}];

// M1 Milestone: Population Selection complete - proceeding to sync
const data = $('Merge and Chunk').first().json;

return [{
  json: {
    ...data,
    milestone: 'M1',
    milestone_name: 'Population Selection',
    milestone_status: 'COMPLETED',
    milestone_timestamp: new Date().toISOString(),
    message: `M1 complete: ${data.total_employees} employees selected in ${data.batch_count} batches. Proceeding to BUPA sync.`
  }
}];

// M2 Milestone: BUPA Sync Execution complete
const jobResult = $('Check Job Status').first().json.result;
const params = $('Merge and Chunk').first().json;

return [{
  json: {
    ...params,
    job_id: $('Schedule BUPA Sync Job').first().json.result.job_id,
    job_status: jobResult.status,
    synced_count: jobResult.synced_count || 0,
    error_count: jobResult.error_count || 0,
    milestone: 'M2',
    milestone_name: 'BUPA Sync Execution',
    milestone_status: 'COMPLETED',
    milestone_timestamp: new Date().toISOString(),
    message: `M2 complete: Job ${jobResult.status}. Synced: ${jobResult.synced_count || 0}, Errors: ${jobResult.error_count || 0}`
  }
}];

// Merge and deduplicate errors from /SHCM/D_BP_SYNC and SLG1
// Field names aligned with agent SyncError model: employee_id, error_class, error_message, error_source, timestamp, related_bp_id
const syncErrors = $('Read Sync Error Log').first().json.result || [];
const slg1Errors = $('Read SLG1 Log').first().json.result || [];

// Normalize both error sources into agent-compatible SyncError format
const normalizeError = (err, source) => ({
  employee_id: err.PERNR || err.pernr || err.employee_id || '',
  error_class: err.MSGNO || err.error_code || err.message_number || '',
  error_message: err.MSGTX || err.error_message || err.message_text || '',
  error_source: source,
  timestamp: err.DATUM || err.timestamp || err.date || new Date().toISOString(),
  related_bp_id: err.PARTNER || err.bp_id || null
});

const allErrors = [
  ...(Array.isArray(syncErrors) ? syncErrors : []).map(e => normalizeError(e, 'BP_SYNC')),
  ...(Array.isArray(slg1Errors) ? slg1Errors : []).map(e => normalizeError(e, 'SLG1'))
];

// Deduplicate by employee_id + error_class combination
const seen = new Set();
const uniqueErrors = allErrors.filter(err => {
  const key = `${err.employee_id}_${err.error_class}_${err.error_source}`;
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

const prevData = $('M2 Milestone Log').first().json;

return [{
  json: {
    ...prevData,
    errors: uniqueErrors,
    error_count: uniqueErrors.length,
    bp_sync_errors: (Array.isArray(syncErrors) ? syncErrors : []).length,
    slg1_errors: (Array.isArray(slg1Errors) ? slg1Errors : []).length,
    deduplicated_count: uniqueErrors.length
  }
}];

// M3 Milestone: Error Log Extraction and AI Analysis complete
const prevData = $('Merge Errors').first().json;
const agentResponse = $('Invoke BUPA Sync Agent').first().json;

let proposals = [];
try {
  const responseText = agentResponse.result || agentResponse.text || JSON.stringify(agentResponse);
  // Try to parse JSON from the agent response
  const jsonMatch = responseText.match(/\[([\s\S]*?)\]/);
  if (jsonMatch) {
    proposals = JSON.parse('[' + jsonMatch[1] + ']');
  }
} catch (e) {
  proposals = [];
}

return [{
  json: {
    ...prevData,
    proposals,
    proposal_count: proposals.length,
    milestone: 'M3',
    milestone_name: 'Error Log Extraction',
    milestone_status: 'COMPLETED',
    milestone_timestamp: new Date().toISOString(),
    message: `M3 complete: ${prevData.error_count} errors found, ${proposals.length} fix proposals generated by AI agent.`
  }
}];

// M3 Milestone: No errors found - skip to report
const prevData = $('Merge Errors').first().json;

return [{
  json: {
    ...prevData,
    proposals: [],
    proposal_count: 0,
    milestone: 'M3',
    milestone_name: 'Error Log Extraction',
    milestone_status: 'COMPLETED',
    milestone_timestamp: new Date().toISOString(),
    message: 'M3 complete: No errors found. Skipping to reconciliation report.'
  }
}];

// Parse agent proposals and categorize by confidence_score (aligned with agent FixProposal model)
const data = $input.first().json;
const proposals = data.proposals || [];

const categorized = {
  high: proposals.filter(p => (p.confidence_score || 0) > 0.8),
  medium: proposals.filter(p => (p.confidence_score || 0) >= 0.5 && (p.confidence_score || 0) <= 0.8),
  low: proposals.filter(p => (p.confidence_score || 0) < 0.5)
};

return [{
  json: {
    ...data,
    categorized_proposals: categorized,
    high_confidence_count: categorized.high.length,
    medium_confidence_count: categorized.medium.length,
    low_confidence_count: categorized.low.length
  }
}];

