// M4 Milestone: Approval workflow complete
const data = $('Parse Agent Proposals').first().json;
const approvalResult = $('Approval Response').first().json.result.response;

return [{
  json: {
    ...data,
    approval_result: approvalResult,
    milestone: 'M4',
    milestone_name: 'Approval Workflow',
    milestone_status: 'COMPLETED',
    milestone_timestamp: new Date().toISOString(),
    message: `M4 complete: Approval result = ${approvalResult}. High: ${data.high_confidence_count}, Medium: ${data.medium_confidence_count}, Low (auto-rejected): ${data.low_confidence_count}`
  }
}];

// Filter to only approved fixes (high + medium confidence)
const data = $input.first().json;
const approvedFixes = [
  ...(data.categorized_proposals.high || []),
  ...(data.categorized_proposals.medium || [])
];

// Create batch items for processing (100 per batch)
const BATCH_SIZE = 100;
const batches = [];
for (let i = 0; i < approvedFixes.length; i += BATCH_SIZE) {
  batches.push(approvedFixes.slice(i, i + BATCH_SIZE));
}

return [{
  json: {
    ...data,
    approved_fixes: approvedFixes,
    approved_fix_count: approvedFixes.length,
    fix_batches: batches,
    fix_batch_count: batches.length
  }
}];

// Prepare batch items for Split In Batches node
const data = $input.first().json;
const items = data.fix_batches.map((batch, idx) => ({
  json: {
    batch_index: idx,
    batch_size: batch.length,
    fixes: batch,
    run_id: data.run_id,
    total_batches: data.fix_batch_count
  }
}));

return items.length > 0 ? items : [{ json: { batch_index: 0, batch_size: 0, fixes: [], run_id: data.run_id, total_batches: 0 } }];

// M5 Milestone: Fix Application & Retry complete
const data = $('Filter Approved Fixes').first().json;

return [{
  json: {
    ...data,
    milestone: 'M5',
    milestone_name: 'Fix Application & Retry',
    milestone_status: 'COMPLETED',
    milestone_timestamp: new Date().toISOString(),
    message: `M5 complete: ${data.approved_fix_count} fixes applied across ${data.fix_batch_count} batches. Re-sync triggered for affected records.`
  }
}];

// Generate Reconciliation Report
const data = $input.first().json;

const total = data.total_employees || 0;
const synced = (data.total_employees || 0) - (data.error_count || 0);
const failed = data.error_count || 0;
const fixed = data.approved_fix_count || 0;
const remainingErrors = Math.max(0, failed - fixed);
const coveragePct = total > 0 ? ((synced + fixed) / total * 100).toFixed(1) : '0.0';

const report = {
  report_title: 'BUPA Sync Reconciliation Report',
  run_id: data.run_id || 'N/A',
  generated_at: new Date().toISOString(),
  summary: {
    total_employees: total,
    successfully_synced: synced,
    initial_errors: failed,
    fixes_applied: fixed,
    remaining_errors: remainingErrors,
    coverage_percentage: parseFloat(coveragePct)
  },
  milestones: [
    { id: 'M1', name: 'Population Selection', status: 'COMPLETED' },
    { id: 'M2', name: 'BUPA Sync Execution', status: 'COMPLETED' },
    { id: 'M3', name: 'Error Log Extraction', status: 'COMPLETED' },
    { id: 'M4', name: 'Approval Workflow', status: data.approval_result ? 'COMPLETED' : 'SKIPPED' },
    { id: 'M5', name: 'Fix Application & Retry', status: fixed > 0 ? 'COMPLETED' : 'SKIPPED' }
  ],
  details: {
    sync_scope: data.sync_scope || 'all_active',
    batch_count: data.batch_count || 0,
    high_confidence_fixes: data.high_confidence_count || 0,
    medium_confidence_fixes: data.medium_confidence_count || 0,
    low_confidence_rejected: data.low_confidence_count || 0,
    approval_result: data.approval_result || 'N/A'
  }
};

const emailBody = `BUPA Sync Reconciliation Report\n` +
  `================================\n` +
  `Run ID: ${report.run_id}\n` +
  `Generated: ${report.generated_at}\n\n` +
  `SUMMARY\n` +
  `-------\n` +
  `Total Employees: ${report.summary.total_employees}\n` +
  `Successfully Synced: ${report.summary.successfully_synced}\n` +
  `Initial Errors: ${report.summary.initial_errors}\n` +
  `Fixes Applied: ${report.summary.fixes_applied}\n` +
  `Remaining Errors: ${report.summary.remaining_errors}\n` +
  `Coverage: ${report.summary.coverage_percentage}%\n\n` +
  `MILESTONES\n` +
  `----------\n` +
  report.milestones.map(m => `${m.id} - ${m.name}: ${m.status}`).join('\n') + '\n\n' +
  `DETAILS\n` +
  `-------\n` +
  `Scope: ${report.details.sync_scope}\n` +
  `Batches: ${report.details.batch_count}\n` +
  `High Confidence Fixes: ${report.details.high_confidence_fixes}\n` +
  `Medium Confidence Fixes: ${report.details.medium_confidence_fixes}\n` +
  `Low Confidence (Rejected): ${report.details.low_confidence_rejected}\n` +
  `Approval Decision: ${report.details.approval_result}`;

return [{
  json: {
    report,
    email_body: emailBody
  }
}];

